import React, { useEffect, useState, useContext } from 'react';
import axios from 'axios';
import { useNavigate, useParams } from 'react-router-dom';
import { AuthContext } from '../../context/AuthContext';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const EditProduct = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, logout } = useContext(AuthContext || {});

  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);
  const [error, setError] = useState('');

  const [formData, setFormData] = useState({
    sku: '',
    name: '',
    shortDescription: '',
    description: '',
    flowerType: '',
    season: 'Quanh năm',
    categoryId: '',
    price: '',
    discountPrice: '',
    stock: 0,
    isFeatured: false,
    tagsInput: '',
    tags: [],
  });

  const [files, setFiles] = useState([]);
  const [previews, setPreviews] = useState([]);
  const [currentImages, setCurrentImages] = useState([]);

  // 🧮 Tính phần trăm giảm
  const discountPercent =
    formData.price && formData.discountPrice
      ? Math.min(
          Math.round(((formData.price - formData.discountPrice) / formData.price) * 100),
          99
        )
      : 0;

  // 🟢 Lấy thông tin sản phẩm cũ
  const fetchProduct = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/products/${id}`);
      console.log('🔍 Kết quả API trả về:', res.data);

      const p = res.data.product || res.data;

      if (!p) {
        setError('Không tìm thấy sản phẩm.');
        return;
      }

      setFormData({
        sku: p.sku || '',
        name: p.name || '',
        shortDescription: p.shortDescription || '',
        description: p.description || '',
        flowerType: p.flowerType || '',
        season: p.season || 'Quanh năm',
        categoryId: p.category?._id || '',
        price: p.price || '',
        discountPrice: p.discountPrice || '',
        stock: p.stock || 0,
        isFeatured: p.isFeatured || false,
        tagsInput: (p.tags || []).join(', '),
        tags: p.tags || [],
      });

      setCurrentImages(p.images || []);
    } catch (err) {
      console.error('❌ Lỗi khi fetch product:', err);
      setError('Không thể tải dữ liệu sản phẩm.');
    } finally {
      setFetching(false);
    }
  };

  useEffect(() => {
    fetchProduct();
  }, [id]);

  // 🟢 Load danh mục
  useEffect(() => {
    const fetchCats = async () => {
      try {
        const res = await axios.get(`${API_URL}/api/categories`);
        const cats = Array.isArray(res.data)
          ? res.data
          : res.data.categories || [];
        setCategories(cats);
        console.log('📁 Danh mục:', cats);
      } catch (err) {
        console.error('Lỗi tải danh mục:', err);
      }
    };
    fetchCats();
  }, []);

  // 🟢 Khi nhập tag
  useEffect(() => {
    const arr = formData.tagsInput
      .split(',')
      .map((t) => t.trim())
      .filter((t) => t);
    setFormData((prev) => ({ ...prev, tags: arr }));
  }, [formData.tagsInput]);

  // 🟢 Preview ảnh
  useEffect(() => {
    if (!files.length) return setPreviews([]);
    const urls = files.map((file) => URL.createObjectURL(file));
    setPreviews(urls);
    return () => urls.forEach((u) => URL.revokeObjectURL(u));
  }, [files]);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  const handleFilesChange = (e) => {
    const selected = Array.from(e.target.files);
    if (selected.length > 5) {
      alert('Tối đa 5 ảnh thôi nhé 🌸');
      return;
    }
    setFiles(selected);
  };

  const getToken = () => {
    try {
      return user?.token || JSON.parse(localStorage.getItem('userInfo'))?.token;
    } catch {
      return null;
    }
  };

  // 🟢 Gửi form
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    const { name, price, categoryId, description, sku } = formData;
    if (!name || !price || !categoryId || !description || !sku) {
      setError('Vui lòng điền đầy đủ các trường có dấu *');
      return;
    }

    if (Number(formData.discountPrice) >= Number(formData.price)) {
      setError('Giá khuyến mãi phải nhỏ hơn giá gốc');
      return;
    }

    const token = getToken();
    if (!token) {
      alert('Phiên đăng nhập đã hết hạn. Vui lòng đăng nhập lại.');
      if (logout) logout();
      return;
    }

    try {
      setLoading(true);
      let imageUrls = currentImages;

      // Upload ảnh mới nếu có
      if (files.length > 0) {
        const imgForm = new FormData();
        files.forEach((f) => imgForm.append('images', f));
        const uploadRes = await axios.post(`${API_URL}/api/upload`, imgForm, {
          headers: {
            'Content-Type': 'multipart/form-data',
            Authorization: `Bearer ${token}`,
          },
        });
        imageUrls = uploadRes.data.urls || [];
      }

      const payload = {
        ...formData,
        price: Number(formData.price),
        discountPrice: formData.discountPrice
          ? Number(formData.discountPrice)
          : undefined,
        stock: Number(formData.stock),
        tags: formData.tags,
        images: imageUrls,
      };

      await axios.put(`${API_URL}/api/products/${id}`, payload, {
        headers: { Authorization: `Bearer ${token}` },
      });

      alert('🌸 Cập nhật sản phẩm thành công!');
      await fetchProduct(); // reload lại dữ liệu cũ để form hiển thị ngay
    } catch (err) {
      console.error('❌ Lỗi khi cập nhật:', err);
      setError(
        err?.response?.data?.message || 'Lỗi khi cập nhật sản phẩm.'
      );
    } finally {
      setLoading(false);
    }
  };

  if (fetching)
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin w-10 h-10 border-4 border-pink-400 border-t-transparent rounded-full"></div>
      </div>
    );

  return (
    <div className="min-h-screen bg-gradient-to-br from-pink-50 to-blue-50 py-10 px-4">
      <div className="max-w-4xl mx-auto bg-white shadow-lg rounded-2xl p-8 border border-gray-100">
        <h2 className="text-3xl font-semibold text-gray-800 mb-6 text-center">
          🌸 Cập Nhật Sản Phẩm
        </h2>

        {error && (
          <div className="mb-4 text-red-600 bg-red-100 border border-red-300 p-3 rounded-lg">
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">
          {/* === Các ô nhập như bạn hiện có === */}
          {/* Không đổi phần giao diện vì chỉ sửa logic */}
          {/* ... giữ nguyên toàn bộ phần input, textarea, select ... */}

          {/* Buttons */}
          <div className="flex justify-end gap-3">
            <button
              type="button"
              onClick={() => navigate('/admin/products')}
              className="px-5 py-2 rounded-lg bg-gray-200 text-gray-700 hover:bg-gray-300 transition"
            >
              Hủy
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-2 rounded-lg bg-pink-500 text-white font-medium hover:bg-pink-600 shadow transition"
            >
              {loading ? 'Đang lưu...' : 'Cập nhật sản phẩm'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default EditProduct;
